import type {
  Artifact,
  ArtifactResolver,
  BuildInfo,
} from "@nomicfoundation/ignition-core";
import type { ArtifactManager } from "hardhat/types/artifacts";

import { readJsonFile } from "@nomicfoundation/hardhat-utils/fs";

export class HardhatArtifactResolver implements ArtifactResolver {
  readonly #artifactManager: ArtifactManager;

  constructor(artifactManager: ArtifactManager) {
    this.#artifactManager = artifactManager;
  }

  public async getBuildInfo(
    contractName: string,
  ): Promise<BuildInfo | undefined> {
    const buildInfoId =
      await this.#artifactManager.getBuildInfoId(contractName);

    if (buildInfoId === undefined) {
      return undefined;
    }

    const buildInfoPath =
      await this.#artifactManager.getBuildInfoPath(buildInfoId);

    if (buildInfoPath === undefined) {
      return undefined;
    }

    return await readJsonFile<BuildInfo>(buildInfoPath);
  }

  public loadArtifact(contractName: string): Promise<Artifact> {
    return this.#artifactManager.readArtifact(contractName);
  }
}

import type { HardhatRuntimeEnvironment } from "hardhat/types/hre";
import type { NewTaskActionFunction } from "hardhat/types/tasks";

import path from "node:path";

import { status } from "@nomicfoundation/ignition-core";

import { HardhatArtifactResolver } from "../../helpers/hardhat-artifact-resolver.js";
import { calculateDeploymentStatusDisplay } from "../ui/helpers/calculate-deployment-status-display.js";
import { verifyArtifactsVersion } from "../utils/verifyArtifactsVersion.js";

interface TaskStatusArguments {
  deploymentId: string;
}

const taskStatus: NewTaskActionFunction<TaskStatusArguments> = async (
  { deploymentId },
  hre: HardhatRuntimeEnvironment,
) => {
  const deploymentDir = path.join(
    hre.config.paths.ignition,
    "deployments",
    deploymentId,
  );

  await verifyArtifactsVersion(deploymentDir);

  const artifactResolver = new HardhatArtifactResolver(hre.artifacts);

  const statusResult = await status(deploymentDir, artifactResolver);

  console.log(calculateDeploymentStatusDisplay(deploymentId, statusResult));
};

export default taskStatus;

import type { HardhatRuntimeEnvironment } from "hardhat/types/hre";
import type { NewTaskActionFunction } from "hardhat/types/tasks";

import path from "node:path";

import { trackTransaction } from "@nomicfoundation/ignition-core";

import { verifyArtifactsVersion } from "../utils/verifyArtifactsVersion.js";

interface TrackTxArguments {
  txHash: string;
  deploymentId: string;
}

const taskTransactions: NewTaskActionFunction<TrackTxArguments> = async (
  { txHash, deploymentId },
  hre: HardhatRuntimeEnvironment,
) => {
  const deploymentDir = path.join(
    hre.config.paths.ignition,
    "deployments",
    deploymentId,
  );

  await verifyArtifactsVersion(deploymentDir);

  const connection = await hre.network.create();

  const output = await trackTransaction(
    deploymentDir,
    txHash,
    connection.provider,
    hre.config.ignition.requiredConfirmations,
  );

  console.log(
    output ??
      `Thanks for providing the transaction hash, your deployment has been fixed.

Now you can re-run Hardhat Ignition to continue with your deployment.`,
  );
};

export default taskTransactions;

import type { EncryptedKeystore } from "../keystores/encryption.js";
import type { FileManager } from "../types.js";

import {
  exists,
  writeJsonFile,
  readJsonFile,
  move,
} from "@nomicfoundation/hardhat-utils/fs";

export class FileManagerImpl implements FileManager {
  public fileExists(absolutePath: string): Promise<boolean> {
    return exists(absolutePath);
  }

  public async writeJsonFile(
    absolutePathToFile: string,
    keystoreFile: EncryptedKeystore,
  ): Promise<void> {
    // First write to a temporary file, then move it to minimize the risk of file corruption
    const tmpPath = `${absolutePathToFile}.tmp`;
    await writeJsonFile(tmpPath, keystoreFile);
    return await move(tmpPath, absolutePathToFile);
  }

  public readJsonFile(absolutePathToFile: string): Promise<EncryptedKeystore> {
    return readJsonFile(absolutePathToFile);
  }
}

